import{_ as e,o as n,c as o,ag as a}from"./chunks/framework.CvgP6Fyv.js";const _=JSON.parse('{"title":"🛡️ 渗透测试实战演练指南","description":"","frontmatter":{"order":1},"headers":[],"relativePath":"security/penetration/intro.md","filePath":"security/penetration/intro.md","lastUpdated":1774465297000}'),i={name:"security/penetration/intro.md"};function r(s,t,l,c,p,d){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="🛡️-渗透测试实战演练指南" tabindex="-1">🛡️ 渗透测试实战演练指南 <a class="header-anchor" href="#🛡️-渗透测试实战演练指南" aria-label="Permalink to &quot;🛡️ 渗透测试实战演练指南&quot;">​</a></h1><p>如果说 CTF 是一场设定好规则的“解谜游戏”，那么真实的渗透测试（Penetration Testing）则是一场没有固定解法的“迷宫探险”。本模块主要沉淀从外网边界突破到内网深处的信息搜集、漏洞利用与权限维持经验。</p><h2 id="🗺️-标准渗透测试模型-ptes" tabindex="-1">🗺️ 标准渗透测试模型 (PTES) <a class="header-anchor" href="#🗺️-标准渗透测试模型-ptes" aria-label="Permalink to &quot;🗺️ 标准渗透测试模型 (PTES)&quot;">​</a></h2><p>真实的攻防演练通常遵循一套严谨的方法论：</p><ol><li><strong>前期交互 (Pre-engagement)：</strong> 明确授权范围（Rules of Engagement）、目标边界。</li><li><strong>情报搜集 (Reconnaissance)：</strong> 子域名爆破、端口扫描、指纹识别、社工信息搜集（信息搜集的广度往往决定了渗透的深度）。</li><li><strong>威胁建模与漏洞分析：</strong> 寻找薄弱点（如遗留的未授权接口、老旧组件的 N-day）。</li><li><strong>漏洞利用 (Exploitation)：</strong> 获取初始立足点（Initial Access），拿到 WebShell 或反弹 Shell。</li><li><strong>后渗透攻击 (Post-Exploitation)：</strong><ul><li>提权（Privilege Escalation：如 Linux SUID 提权、Windows 内核漏洞提权）。</li><li>凭证窃取（抓取 Hash/明文密码）。</li><li><strong>内网横向移动 (Lateral Movement)：</strong> 搭建代理隧道，跨越网段，直捣核心域控。</li></ul></li><li><strong>痕迹清理与报告：</strong> 形成闭环。</li></ol><div class="warning custom-block"><p class="custom-block-title">⚠️ 授权红线</p><p>本目录下的所有技术分析与 Payload 仅用于本地靶场环境（如 HTB, VulnHub）的安全研究与技术提升。<strong>未经授权的渗透测试属于违法行为。</strong> 务必坚守安全从业者的底线。</p></div>',6)])])}const u=e(i,[["render",r]]);export{_ as __pageData,u as default};
